import { useState, useRef } from "react";
import { SettingsTabs } from "../../shared/components/SettingsTabs";
import SettingsPageLayout from "./SettingsPageLayout";
import { useQuery } from "@tanstack/react-query";
import { api } from "../../api/client";
import {
  fetchServiceHealth,
  type ServiceStatus,
  type ServiceHealth,
} from "../../api/health";
import TimeSeriesChart from "../../shared/components/charts/TimeSeriesChart";

// ── Status badge ──────────────────────────────────────────────────────────────

const STATUS_COLORS: Record<
  ServiceStatus,
  { bg: string; text: string; label: string }
> = {
  healthy: {
    bg: "color-mix(in srgb, var(--io-success) 12%, transparent)",
    text: "var(--io-success)",
    label: "Ready",
  },
  degraded: {
    bg: "color-mix(in srgb, var(--io-warning) 15%, transparent)",
    text: "var(--io-warning)",
    label: "Degraded",
  },
  unhealthy: {
    bg: "color-mix(in srgb, var(--io-danger) 12%, transparent)",
    text: "var(--io-danger)",
    label: "Not Ready",
  },
  unknown: {
    bg: "var(--io-surface-secondary)",
    text: "var(--io-text-muted)",
    label: "Unknown",
  },
};

function StatusBadge({ status }: { status: ServiceStatus }) {
  const c = STATUS_COLORS[status];
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: "5px",
        fontSize: "12px",
        padding: "3px 10px",
        borderRadius: "100px",
        background: c.bg,
        color: c.text,
        fontWeight: 700,
      }}
    >
      <span
        aria-hidden="true"
        style={{
          width: "6px",
          height: "6px",
          borderRadius: "50%",
          background: c.text,
          flexShrink: 0,
        }}
      />
      {c.label}
    </span>
  );
}

// ── Service metadata ──────────────────────────────────────────────────────────

const SERVICE_INFO: Record<
  string,
  { display: string; description: string; impact: string }
> = {
  "api-gateway": {
    display: "API Gateway",
    description: "HTTP routing, JWT validation, RBAC enforcement",

  });
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function StatusBadge({ status }: { status: string }) {
  const colors: Record<string, { bg: string; color: string }> = {
    completed: { bg: "var(--io-success-subtle)", color: "var(--io-success)" },
    running: { bg: "var(--io-accent-subtle)", color: "var(--io-accent)" },
    pending: { bg: "var(--io-warning-subtle)", color: "var(--io-warning)" },
    failed: { bg: "var(--io-danger-subtle)", color: "var(--io-danger)" },
    cancelled: {
      bg: "var(--io-surface-tertiary)",
      color: "var(--io-text-muted)",
    },
    partial: { bg: "var(--io-warning-subtle)", color: "var(--io-warning)" },
    ok: { bg: "var(--io-success-subtle)", color: "var(--io-success)" },
    error: { bg: "var(--io-danger-subtle)", color: "var(--io-danger)" },
  };
  const style = colors[status] ?? {
    bg: "var(--io-surface-tertiary)",
    color: "var(--io-text-muted)",
  };
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "11px",
        fontWeight: 600,
        background: style.bg,
        color: style.color,
        textTransform: "capitalize",
      }}
    >
      {status}
    </span>
  );
}

function DomainBadge({ domain }: { domain: string }) {
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "4px",
        fontSize: "11px",
        fontWeight: 500,
        background: "var(--io-accent-subtle)",
        color: "var(--io-accent)",
        textTransform: "capitalize",

  active: "var(--io-success)",
  inactive: "var(--io-text-muted)",
  connecting: "var(--io-warning)",
  error: "var(--io-danger)",
};

function StatusBadge({ status }: { status: string }) {
  const color = STATUS_COLORS[status] ?? "var(--io-text-muted)";
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: "5px",
        padding: "2px 8px",
        borderRadius: "9999px",
        fontSize: "11px",
        fontWeight: 600,
        background: `color-mix(in srgb, ${color} 12%, transparent)`,
        color,
        border: `1px solid color-mix(in srgb, ${color} 25%, transparent)`,
